  Card,
  Divider,
  ConfigProvider,
  Space,
  Typography,
  message,
  Alert,
} from 'antd';
import dayjs from 'dayjs';
import { canvasList, defaultCanvasId, type CanvasOption } from '../../mock/retargetConfig';

const { Text } = Typography;
const { Option } = Select;

