   305→        onCancel={onCancel}
   306→        width={720}
   307→        footer={[
   308→          <Button key="cancel" onClick={onCancel}>
   309→            取消
   310→          </Button>,
   311→          <Button key="save" onClick={handleSave} disabled={configMode === 'select'}>
   312→            保存
   313→          </Button>,
   314→          <Button
   315→            key="submit"
   316→            type="primary"
   317→            onClick={handleSubmit}
   318→            disabled={isGoButtonDisabled}
   319→          >
   320→            {isBuilding ? '构建中...' : '去配置画布'}
   321→          </Button>,
   322→        ]}
   323→      >
   324→        <Form
   325→          form={form}
   326→          layout="vertical"
   327→          initialValues={{
   328→            scene: 'unverified',
   329→            couponIds: [],
   330→            isUpdateEnabled: false,
   331→          }}
   332→        >
   333→          {/* 区域一：关联画布 */}
   334→          <div style={styles.sectionTitle}>关联画布</div>
   335→
   336→          {/* 关联画布 - 只读显示 */}
   337→          <Form.Item
   338→            label="关联画布"
   339→            name="canvasId"
   340→            rules={[{ required: true, message: '请选择关联画布' }]}
   341→            style={{ marginBottom: '4px' }}
   342→          >
   343→            <Select
   344→              showSearch
   345→              placeholder="请选择关联画布"
   346→              onChange={handleCanvasChange}
   347→              filterOption={filterCanvasOption}
   348→              optionFilterProp="children"
   349→              disabled
   350→            >
   351→              {canvasList.map(canvas => renderCanvasOption(canvas))}
   352→            </Select>
   353→          </Form.Item>
   354→
   355→          {/* 展开/折叠画布配置信息 */}
   356→          <Form.Item label=" " style={{ marginBottom: '8px' }}>
   357→            <Button
   358→              type="link"
   359→              onClick={() => setConfigExpanded(!configExpanded)}
   360→              style={{ padding: 0, height: 'auto', marginLeft: '-12px' }}
   361→            >
   362→              {configExpanded ? '收起' : '查看'}关联画布配置信息
   363→            </Button>
