    name: '新用户领券未核销召回',
    status: 'completed',
    scene: 'unverified',
    couponIds: ['coupon-1'],
    issueDate: '2026-04-01',
    isUpdateEnabled: true,
    expiryDate: '2026-05-01',
    createdAt: '2026-04-05 10:30:00',
  },
  {
    id: 'preset-2',
    name: '会员日券已核销复购',
    status: 'building',
    scene: 'verified',
    couponIds: ['coupon-4', 'coupon-5'],
    dateRange: ['2026-03-01', '2026-03-31'],
    isUpdateEnabled: false,
    createdAt: '2026-04-06 14:20:00',
  },
];

// 样式定义 - 使用 antd 的 style prop
const styles = {
  sectionTitle: {
    fontSize: '14px',
    fontWeight: 600,
    color: '#333',
    marginBottom: '8px',
  },
  configInfoStyle: {
    backgroundColor: '#f5f5f5',
    borderRadius: '6px',
    padding: '12px 16px',
    marginTop: '8px',
  },
  dividerStyle: {
    margin: '16px 0',
  },
